const items = $input.all();

const categories = {
  active: [],
  new: [],
  removed: [],
  changed: [],
};

const seen = new Set();
let previousTotal = 0;

items.forEach((item) => {
  const row = item?.json || {};

  if (row.previous_total !== undefined && row.previous_total !== null) {
    const parsed = Number(row.previous_total);
    if (Number.isFinite(parsed)) previousTotal = parsed;
    return;
  }

  const status = row.status;
  const creativeId = row.creative_id;
  if (status in categories && creativeId) {
    const key = status + ':' + creativeId;
    if (!seen.has(key)) {
      seen.add(key);
      categories[status].push(row);
    }
  }
});

const currentAdsTotal =
  categories.active.length + categories.new.length + categories.changed.length;

return [
  {
    json: {
      summary: {
        total_ads: currentAdsTotal,
        last_week: previousTotal,
        added_count: categories.new.length,
        removed_count: categories.removed.length,
        changed_count: categories.changed.length,
        active_count: categories.active.length,
      },
      ...categories,
    },
  },
];

// incoming: [{ latest_date: something }]
const raw = new Date($json.latest_date);

// Convert to YYYY-MM-DD
const isoDate = raw.toISOString().split("T")[0];

return [
  {
    normalized_date: isoDate
  }
];
